SELECT id, user_id, agent_id, session_id, memory_type, content, metadata::text AS metadata, embedding::text AS embedding, created_at, updated_at, (embedding <-> #{vectorLiteral}::vector) AS distance FROM long_term_memory WHERE user_id = CAST(#{userId} AS uuid)
AND memory_type IN
#{type}
ORDER BY embedding <-> #{vectorLiteral}::vector LIMIT #{limit}

